pre.code:
import { createStore } from 'metaowl'

const store = createStore({
  count: 0,
  user: null
})

// Access state directly - it's reactive!
store.count

// Modify state directly
store.count++

// Use $patch for batch updates
store.$patch({ count: 10, user: { name: 'John' } })

// Reset to initial state
store.$reset()

// Access state directly - reactive!
store.count

// Modify state directly
store.count = 5

// Use $patch for batch updates
store.$patch({ count: 10, user: { name: 'John' } })

// Reset to initial state
store.$reset()

import { createStore, createPersistencePlugin } from 'metaowl'

const store = createStore({
  state: { theme: 'light' },
  plugins: [
    createPersistencePlugin({ key: 'app-state' })
  ]
})
